// ---------------------------------------------------------------------------
// Helix TypeScript Client & React Hooks
// ---------------------------------------------------------------------------

export interface HelixConfig {
    baseUrl: string;
    headers?: Record<string, string>;
}

export class KVServiceClient {
    constructor(private config: HelixConfig) {}

    async Get(req: GetRequest): Promise<GetResponse> {
        const headers = { 'Content-Type': 'application/json', ...this.config.headers };
        const url = `${this.config.baseUrl}/v1.KVService/Get`;
        const res = await fetch(url, {
            method: 'POST',
            headers,
            body: JSON.stringify(req)
        });
        if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`);
        const data = await res.json();
        return new GetResponse(data);
    }

    async Set(req: SetRequest): Promise<SetResponse> {
        const headers = { 'Content-Type': 'application/json', ...this.config.headers };
        const url = `${this.config.baseUrl}/v1.KVService/Set`;
        const res = await fetch(url, {
            method: 'POST',
            headers,
            body: JSON.stringify(req)
        });
        if (!res.ok) throw new Error(`HTTP error! status: ${res.status}`);
        const data = await res.json();
        return new SetResponse(data);
    }

}

// ---------------------------------------------------------------------------
// React Hooks (Usage: import { useState, useEffect } from 'react'; ...)
// ---------------------------------------------------------------------------
export function useGet(client: KVServiceClient, req: GetRequest | null) {
    const [data, setData] = (<any>window).React?.useState<GetResponse | null>(null) || [null, () => {}];
    const [loading, setLoading] = (<any>window).React?.useState<boolean>(false) || [false, () => {}];
    const [error, setError] = (<any>window).React?.useState<Error | null>(null) || [null, () => {}];

    (<any>window).React?.useEffect(() => {
        if (!req) return;
        let active = true;
        setLoading(true);
        setError(null);

        client.Get(req)
            .then(res => {
                if (active) { setData(res); setLoading(false); }
            })
            .catch(err => {
                if (active) { setError(err); setLoading(false); }
            });

        return () => { active = false; };
    }, [client, JSON.stringify(req)]);

    return { data, loading, error };
}

export function useSet(client: KVServiceClient, req: SetRequest | null) {
    const [data, setData] = (<any>window).React?.useState<SetResponse | null>(null) || [null, () => {}];
    const [loading, setLoading] = (<any>window).React?.useState<boolean>(false) || [false, () => {}];
    const [error, setError] = (<any>window).React?.useState<Error | null>(null) || [null, () => {}];

    (<any>window).React?.useEffect(() => {
        if (!req) return;
        let active = true;
        setLoading(true);
        setError(null);

        client.Set(req)
            .then(res => {
                if (active) { setData(res); setLoading(false); }
            })
            .catch(err => {
                if (active) { setError(err); setLoading(false); }
            });

        return () => { active = false; };
    }, [client, JSON.stringify(req)]);

    return { data, loading, error };
}

